review_findings.suggestion:
JSON.parse後にバリデーション関数を適用し、(1) typeof parsed === 'object' && parsed !== null && !Array.isArray(parsed) を確認、(2) Object.values(parsed).every(v => typeof v === 'boolean') を確認、(3) Object.keys(parsed).length が上限（例: 1000）以下であることを確認する。バリデーション失敗時はデフォルト値 {} を返す。具体的には以下のようなバリデーション関数を追加する:

function validateGroupCollapsed(parsed: unknown): Record<string, boolean> {
  if (typeof parsed !== 'object' || parsed === null || Array.isArray(parsed)) return {};
  const obj = parsed as Record<string, unknown>;
  const keys = Object.keys(obj);
  if (keys.length > 1000) return {};
  const result: Record<string, boolean> = {};
  for (const key of keys) {
    if (typeof obj[key] === 'boolean') result[key] = obj[key] as boolean;
  }
  return result;
}
